function.arguments:
{"cmd":"# Create Nginx configuration for serving branches on HTTPS 8443
cat > /etc/nginx/sites-available/git-deploy << 'EOF'
server {
    listen 8443 ssl;
    server_name localhost;

    ssl_certificate /etc/nginx/ssl/server.crt;
    ssl_certificate_key /etc/nginx/ssl/server.key;

    root /var/www/html;

    location / {
        try_files $uri $uri/ =404;
    }
}
EOF

# Remove default site and enable our config
rm -f /etc/nginx/sites-enabled/default
ln -sf /etc/nginx/sites-available/git-deploy /etc/nginx/sites-enabled/git-deploy

# Create the dev directory
mkdir -p /var/www/html/dev

echo "Nginx config created""}
